# NL HHH.  Heerhugowaard - Hoorn
#
let hh = path("d3.nl.hhh");

with detail = 3,
     railway = :first :cat:dc15 :pax
{
    # point.nl.Heerhugowaard  nl.DHA

    with link = "line.nl.HHH" {
        track(:station,
                hh[:her.yh, :her.xh] >> 0.5md << 0.5mt
            ..  hh[:mid - 0.5sw, :mid - 0.49sw]
        );
    }

    with link = "point.nl.Middelweg" {
        track(hh[:mid - 0.5sw, :mid + 0.5sw]);
        marker(:right :de.hp :removed, hh[:mid] >> 0.5mt);
        slabel(:nw :removed, hh[:mid] >> 0.5mt >> 1sh + (-3dt, 0.3dt),
            "Middelweg"
        );
    }

    with link = "line.nl.HHH" {
        track(hh[:mid + 0.49sw, :mid + 2.01km]);
        line_label(:left:s, hh[:mid + 2km] << 0.5mt, "HHH");
        track(hh[:mid + 1.99km, :obd - 0.49sw]);
    }

    with link = "point.nl.Obdam" {
        track(hh[:obd - 0.5sw, :obd + 0.5sw]);
        marker(:left :de.bf, hh[:obd] << 0.5mt);
        slabel(:top, hh[:obd] << 0.5mt << 1sh + (0.8dt, -0.4dt), "Obdam");
    }

    with link = "line.nl.HHH" {
        track(hh[:obd + 0.49sw, :spi - 0.49sw]);
    }

    with link = "point.nl.Spierdijk" {
        track(hh[:spi - 0.5sw, :spi + 0.5sw]);
        marker(:right :de.hp :removed, hh[:spi] >> 0.5mt);
        slabel(:ne :removed, hh[:spi] >> 0.5mt >> 1sh + (-1.5dt, -0.8dt),
            "Spierdijk"
        );
    }

    with link = "line.nl.HHH" {
        track(hh[:spi + 0.49sw, :zui - 0.49sw]);
    }

    with link = "point.nl.Zuidermeer" {
        track(hh[:zui - 0.5sw, :zui + 0.5sw]);
        marker(:right :de.hp :removed, hh[:zui] >> 0.5mt);
        slabel(:ne :removed, hh[:zui] >> 0.5mt >> 1sh + (-1.5dt, -0.8dt),
            "Zuidermeer"
        );
    }

    with link = "line.nl.HHH" {
        track(hh[:zui + 0.49sw, :bob - 0.49sw]);
    }

    with link = "point.nl.Bobeldijk-Berkhout" {
        track(hh[:bob - 0.5sw, :bob + 0.5sw]);
        marker(:right :de.hp :removed, hh[:bob] >> 0.5mt);
        slabel(:ne :removed, hh[:bob] >> 0.5mt >> 1sh + (-1.5dt, -0.8dt),
            "Bobeldijk-Berkhout*"
        );
    }

    with link = "line.nl.HHH" {
        track(hh[:bob + 0.5sw, :bob + 1.11km]);
        line_label(:left:sw, hh[:bob + 1.1km] << 0.5mt, "HHH");
        track(hh[:bob + 1.09km, :hoo.xh - 1md]);
        track(:ror,
                hh[:hoo.xh - 1.1md, :hoo.xh - 1md]
            ..  hh[:hoa, :hoa + 0.1dl] << 0.5md << 1ms << 0.5mt
        );
        track(:ror, hh[:hoa, :hoo - 199m] << 0.5md << 1ms << 0.5mt);
    }

    # point.nl.Hoorn  nl.ZEH
}

